g.script:
webMI.proxy({"":[function(webMI,window,document,self){var idGlass = "id_Cabinet_glass";
var idAlarm = "id_Cabinet_alarm";
var idBancoAcceso = "id_Cabinet_banco-acceso";
var idBanco = "id_Cabinet_banco";
var idDevicesInfo = "DevicesInfo";

var MPXoneType;
var showCircuit = false;
var showValve = false;

webMI.addOnload(function(e) {
	document.getElementById(idGlass).setAttribute("opacity","0");
	document.getElementById(idAlarm).setAttribute("opacity","0");
	document.getElementById("EnterOffAnimation").beginElement();

	MPXoneType = Number(webMI.query["MPXoneType"]);

	webMI.data.read("MPXone_BossMap/$dev$.Digitals.| BAS_swVers", function (e){

		var softwareVer = e.value;	

		switch (MPXoneType) {
			case 0: // Basic
				if (softwareVer >= 2100){
					showCircuit = true;
					showValve = false;
				}
				break;

			case 1: // Medium
				if (softwareVer >= 2200){
					showCircuit = true;
					showValve = true;
				}
				break;

			case 2: // Advanced
				if (softwareVer >= 2200){
					showCircuit = true;
					showValve = true;
				}
				break;

			default:
				console.log("Unknown MPXone type!");
		}

		loadCircuit();
	});


});

webMI.data.subscribeBlock([
	"MPXone_BossMap/$dev$.Digitals.| BAS_DO_Lht",	
	"MPXone_BossMap/$dev$.Digitals.| BAS_DO_mLht"],
	function (e){

		var LocalLightOn = e[0].value;
		var NetworkLightOn = e[1].value;

		if (LocalLightOn || NetworkLightOn)
			document.getElementById(idBancoAcceso).setAttribute("opacity","1");
		else
			document.getElementById(idBancoAcceso).setAttribute("opacity","0");
});


//***************************************************
//********************** Alarms *********************
//***************************************************

webMI.data.subscribe("MPXone_BossMap/$dev$.Digitals.Presenza di allarme | BAS_OrAlrm", function (e){

	if (e.value)
		document.getElementById(idAlarm).setAttribute("opacity","1");
	else	
		document.getElementById(idAlarm).setAttribute("opacity","0");

});


//***************************************************
//***************** Direct commands *****************
//***************************************************

function buttonMng(commandPar,onAnimation,offAnimation,buttonId,ledStatusId,feedback1,feedback2) {

	var loadFirstTime = true;
	var commandValue = false;
	var buttonStatus = false;

	webMI.data.subscribe(commandPar, function (e){

		commandValue = e.value;	

		if (loadFirstTime || commandValue != buttonStatus){

			if (commandValue)
				document.getElementById(onAnimation).beginElement();
			else
				document.getElementById(offAnimation).beginElement();

			loadFirstTime = false;
			buttonStatus = commandValue;
		}
	});

	webMI.addEvent(buttonId, "click", function(e) {

		if (buttonStatus){
			buttonStatus = false;
			webMI.data.write([commandPar], ["0"]);
		}else{			
			buttonStatus = true;
			webMI.data.write([commandPar], ["1"]);
		}

	});

	if (feedback2 == null){

		webMI.data.subscribe(feedback1, function (e){

			var functionStatus = e.value;	

			if (functionStatus){
				document.getElementById(ledStatusId).setAttribute("fill","#70B62C");
			}else{
				document.getElementById(ledStatusId).setAttribute("fill","#B5B9C0");
			}
		});

	}else{
		webMI.data.subscribeBlock([
			feedback1,	
			feedback2],
			function (e){

				var feedback1On = e[0].value;
				var Feedback2On = e[1].value;

				if (feedback1On || Feedback2On)
					document.getElementById(ledStatusId).setAttribute("fill","#70B62C");
				else
					document.getElementById(ledStatusId).setAttribute("fill","#B5B9C0");
		});
	}

}

//OnOff button
buttonMng("MPXone_BossMap/$dev$. | BAS_ON","OnAnimation","OffAnimation","OnOffButton","OnOffLedStatus","MPXone_BossMap/$dev$.Digitals. | UnitOn",null);

//Lights
buttonMng("MPXone_BossMap/$dev$. | BAS_Lht","LightsOnAnimation","LightsOffAnimation","LightButton","LightLedStatus","MPXone_BossMap/$dev$.Digitals.| BAS_DO_Lht","MPXone_BossMap/$dev$.Digitals.| BAS_DO_mLht");

//Defrost
buttonMng("MPXone_BossMap/$dev$. | BAS_Dfr","DefrostOnAnimation","DefrostOffAnimation","DefrostButton","DefrostLedStatus","MPXone_BossMap/$dev$.Digitals. | BAS_Dfr",null);

//Network defrost
buttonMng("MPXone_BossMap/$dev$. | BAS_LanDEF_cmd","NetDefrostOnAnimation","NetDefrostOffAnimation","NetworkDefrostButton","NetworkDefrostLedStatus","MPXone_BossMap/$dev$.Digitals. | BAS_LanDEF_cmd",null);

//Clean
buttonMng("MPXone_BossMap/$dev$. | BAS_ManCln","CleanOnAnimation","CleanOffAnimation","CleanButton","CleanLedStatus","MPXone_BossMap/$dev$.Digitals. | BAS_CLn",null);

//Continuous cycle
buttonMng("MPXone_BossMap/$dev$. | BAS_ManCnt_spv","ContinuousOnAnimation","ContinuousOffAnimation","ContCycleButton","ContCycleLedStatus","MPXone_BossMap/$dev$.Digitals. | BAS_ManCnt",null);


//***************************************************
//***************** Circuit details *****************
//***************************************************

var idCircuitCap = "id_Circuit_circuit-cap";
var idCircuitEev = "id_Circuit_circuit-eev";
var idFullCircuitCap = "id_Circuit_fullcircuit-cap";
var idFullCircuitEev = "id_Circuit_fullcircuit-eev";

var valveType = 0;
var compCh = 0;

function UpdateCircuitView(){

	var circuitType;

	var valvePresent = valveType > 0;
	var compPresent = compCh > 0;

	if (valvePresent && compPresent)
		circuitType = 3;
	else if (compPresent && !valvePresent)
		circuitType = 2;
	else if (valvePresent && !compPresent)
		circuitType = 1;
	else
		circuitType = 0;

	if (circuitType != 0)
		document.getElementById(idCircuitCap).setAttribute("opacity","0");
	if (circuitType != 1)
		document.getElementById(idCircuitEev).setAttribute("opacity","0");
	if (circuitType != 2)
		document.getElementById(idFullCircuitCap).setAttribute("opacity","0");
	if (circuitType != 3)
		document.getElementById(idFullCircuitEev).setAttribute("opacity","0");

	switch (circuitType) {
		case 0: //Base circuit without exv valve
			document.getElementById(idCircuitCap).setAttribute("opacity","1");
			break;
		case 1: //Base circuit with exv valve
			document.getElementById(idCircuitEev).setAttribute("opacity","1");
			break;
		case 2: //Full circuit without exv valve
			document.getElementById(idFullCircuitCap).setAttribute("opacity","1");
			break;
		case 3: //Full circuit with exv valve
			document.getElementById(idFullCircuitEev).setAttribute("opacity","1");
			break;
	}

	webMI.trigger.fire("UpdateCircuitType",{
		circuitType: circuitType
	});
}

// Show circuit only on new software releases
function loadCircuit(){

	var idCircuitButtons = "CircuitButtons";
	if (showCircuit){

		if (showValve){

			webMI.data.subscribeBlock([
				"MPXone_BossMap/$dev$.Integers. | MED_P1",
				"MPXone_BossMap/$dev$.Integers. | MED_/AG"],
				function (e){

				valveType = e[0].value;
				compCh = e[1].value;

				UpdateCircuitView();
			});

		}else{

			valveType = 0;
			compCh = 0;

			UpdateCircuitView();
		}

		var circuitViewOn = false;

		var InputsOffsetX = -600;
		var showValveInputs = false;
		var SH_SetY = 0;

		var idCircuit = "id_Circuit";

		var idCabinetButtons = "CabinetButtons";

		var idMainInfo = "MainInfo";
		var idCircuitInfo = "CircuitInfo";

		var idSH_Set = "SH_Set";
		var idExvManPosEn = "ExvManPosEn";
		var idExvManPosVal = "ExvManPosVal";

		var bancoDoc = document.getElementById("banco");

		webMI.addEvent("LookInsideButton", "click", function(e) {

			if (circuitViewOn){

				circuitViewOn = false;

				////Cabinet and circuit
				webMI.gfx.setY(idCircuit,-1080);
				document.getElementById(idBanco).setAttribute("opacity","1");

				//Main and circuit info
				webMI.gfx.setX(idCircuitInfo,2000);
				webMI.gfx.setX(idMainInfo,1570);

				//Inputs
				webMI.gfx.setMoveX(idSH_Set,0);
				webMI.gfx.setMoveX(idExvManPosEn,0);
				webMI.gfx.setMoveX(idExvManPosVal,0);

				//Buttons
				webMI.gfx.setMoveX(idCircuitButtons, 0);
				webMI.gfx.setMoveX(idCabinetButtons, 0);

				//Circuit info
				webMI.gfx.setY(idDevicesInfo,1080);

			}else{

				circuitViewOn = true;

				//Cabinet and circuit
				webMI.gfx.setY(idCircuit,0);
				document.getElementById(idBanco).setAttribute("opacity","0.3");

				//Main and circuit info
				webMI.gfx.setX(idMainInfo,2000);
				webMI.gfx.setX(idCircuitInfo,1570);

				//Inputs		
				if (showValveInputs){
					webMI.gfx.setMoveX(idSH_Set, InputsOffsetX);
					webMI.gfx.setMoveX(idExvManPosEn, InputsOffsetX);
					webMI.gfx.setMoveX(idExvManPosVal, InputsOffsetX);
				}else{
					webMI.gfx.setMoveX(idSH_Set,0);
					webMI.gfx.setMoveX(idExvManPosEn,0);
					webMI.gfx.setMoveX(idExvManPosVal,0);
				}

				//Buttons
				webMI.gfx.setMoveX(idCabinetButtons, -500);
				webMI.gfx.setMoveX(idCircuitButtons, 500);

				//Circuit info
				webMI.gfx.setY(idDevicesInfo,0);

			}

		});

		//Input boxes
		webMI.trigger.connect("SetInputsPos", function(e){
			showValveInputs = e.value.showValveInputs;
			SH_SetY = e.value.SH_SetY;

			webMI.gfx.setMoveY(idSH_Set,SH_SetY);
			webMI.gfx.setMoveY(idExvManPosEn,SH_SetY);
			webMI.gfx.setMoveY(idExvManPosVal,SH_SetY);

		});

	}else{ //If circuit is not showed, remove look inside button and show functions buttons

		var idLookInsideGroup = "LookInsideGroup";

		webMI.gfx.setMoveX(idLookInsideGroup, -500);
		webMI.gfx.setMoveX(idCircuitButtons, 500);
		webMI.gfx.setMoveY(idCircuitButtons, 460);

	}
}
},{"CircuitInfo":["23",{}],"DevicesInfo":["22",{}],"ExvManPosEn":["27",{"base":{v:"MPXone_BossMap/$dev$.Digitals.Abilitazione posizionamento manuale valvola di espansione | MED_PMP"},"color_off":{v:"#ffffff"},"color_on":{v:"#ffffff"},"color_rail_off":{v:"#e0e0e0"},"color_rail_on":{v:"#009EE2"},"read_delay":{v:"15"},"readonly":{v:"false"}}],"ExvManPosVal":["26",{"base":{v:"MPXone_BossMap/$dev$.Integers.Posizione manuale valvola | MED_PMu"},"fill":{v:"#F0F0F0"},"fillColorInactive":{v:"#F0F0F0"},"focusStrokeColor":{v:"#F0F0F0"},"fontColor":{v:"#009EE2"},"fontSize":{v:"24"},"max":{v:"100"},"min":{v:"0"},"text-anchor":{v:"start"},"unit":{v:"%"}}],"MainInfo":["3",{}],"SH_Set":["26",{"base":{v:"MPXone_BossMap/$dev$.Analogs.Set point surriscaldamento | MED_P3"},"fill":{v:"#F0F0F0"},"fillColorInactive":{v:"#F0F0F0"},"focusStrokeColor":{v:"#F0F0F0"},"fontColor":{v:"#009EE2"},"fontSize":{v:"24"},"max":{v:"25"},"min":{v:"0"},"postDecimal":{v:"1"},"text-anchor":{v:"start"},"unit":{v:"K"}}],"id_Cabinet":["1",{}],"id_Circuit":["2",{}]},{"MPXoneType":"0"}],"23":[function(webMI,window,document,self){var idCircInfoBackground = "CircInfoBackground";
var idCircInfoShape = "CircInfoShape";
var idCompInfo = "CompInfo";
var idValveInfo = "ValveInfo";

var CondTempAinCh = 0;

webMI.data.subscribe("MPXone_BossMap/$dev$.Integers. | MED_/Fo", function (e){

	CondTempAinCh = e.value;	

});

var circuitType = 0;
var valvePresent = false;
var compPresent = false;

webMI.trigger.connect("UpdateCircuitType", function(e){
	circuitType = e.value.circuitType;

	switch (circuitType) {
		case 0: //Base circuit without exv valve
			valvePresent = false;
			compPresent = false;
			break;
		case 1: //Base circuit with exv valve
			valvePresent = true;
			compPresent = false;
			break;
		case 2: //Full circuit without exv valve
			valvePresent = false;
			compPresent = true;
			break;
		case 3: //Full circuit with exv valve
			valvePresent = true;
			compPresent = true;
			break;
	}

	if (CondTempAinCh == 0)
		compPresent = false;

	var showValveInputs;
	var SH_SetY;

	//Define displays positions
	if (compPresent)
		webMI.gfx.setX(idCompInfo,0);
	else
		webMI.gfx.setX(idCompInfo,400);

	if (valvePresent){
		if (compPresent){
			webMI.gfx.setY(idValveInfo,175);
			SH_SetY = 376;
		}else{
			webMI.gfx.setY(idValveInfo,108);
			SH_SetY = 309;
		}
		webMI.gfx.setX(idValveInfo,0);
		showValveInputs = true;
	}else{
		webMI.gfx.setX(idValveInfo,400);
		showValveInputs = false;
		SH_SetY = 0;
	}

	//Input boxes
	webMI.trigger.fire("SetInputsPos",{
		showValveInputs: showValveInputs,
		SH_SetY: SH_SetY
	}); 	

	//Define background height
	if (compPresent && !valvePresent)
		webMI.gfx.setHeight(idCircInfoBackground, "153");
	else if (valvePresent && !compPresent)
		webMI.gfx.setHeight(idCircInfoBackground, "622");
	else if (valvePresent && compPresent)
		webMI.gfx.setHeight(idCircInfoBackground, "689");

	//Hide Circuit info if there are no Info to show

	if (!compPresent && !valvePresent){
		webMI.gfx.setMoveX(idCircInfoShape,400);
	}else{
		webMI.gfx.setMoveX(idCircInfoShape,0);
	}

});
},{"CompInfo":["24",{}],"ValveInfo":["25",{}]},{}],"22":[function(webMI,window,document,self){MPXoneType = Number(webMI.query["MPXoneType"]);

var isBasic = MPXoneType == 0;	

//***************************************************
//***************** Evaporator fan ******************
//***************************************************	

if (isBasic){

	webMI.data.subscribe("MPXone_BossMap/$dev$.Digitals. | BAS_DO_Fan",
		function (e){

			var DoutStatus = e.value;

			if (DoutStatus)
				valueToPrint = "ON";
			else
				valueToPrint = "OFF";

			webMI.gfx.setText("FanStatus",valueToPrint);
	});

}else{

	webMI.data.subscribeBlock([
		"MPXone_BossMap/$dev$.Integers. | BAS_/AA",
		"MPXone_BossMap/$dev$.Analogs. | MED_FAA",
		"MPXone_BossMap/$dev$.Digitals. | BAS_DO_Fan"],
		function (e){

			var AoutCh = e[0].value;
			var AoutSpeed = e[1].value;
			var DoutStatus = e[2].value;

			var valueToPrint = "";

			if (AoutCh != 0){
				valueToPrint = AoutSpeed.toFixed(1) + " %";
			}else{
				if (DoutStatus)
					valueToPrint = "ON";
				else
					valueToPrint = "OFF";
			}

			webMI.gfx.setText("FanStatus",valueToPrint);
	});
}

//***************************************************
//***************** Expansion valve *****************
//***************************************************	

var idValveOpeningGroup = "ValveOpeningGroup";

if (isBasic){

	webMI.gfx.setMoveY(idValveOpeningGroup, 1080);

}else{

	webMI.data.subscribeBlock([
		"MPXone_BossMap/$dev$.Integers. | MED_P1",
		"MPXone_BossMap/$dev$.Integers. | MED_EEV"],
		function (e){

			var ValveType = e[0].value;
			var ValveOpening = e[1].value;

			var valueToPrint = "";

			if (ValveType != 0){ //Valve present

				valueToPrint = ValveOpening + " %";
				webMI.gfx.setMoveY(idValveOpeningGroup, 0);

			}else{ //Valve not present
				webMI.gfx.setMoveY(idValveOpeningGroup, 1080);
			}

			webMI.gfx.setText("ValveOpening",valueToPrint);
	});
}

//***************************************************
//***************** Condenser fan *******************
//***************************************************	

var idCondFanGroup = "CondFanGroup";

if (isBasic){

	webMI.gfx.setMoveY(idCondFanGroup, 1080);

}else{

	webMI.data.subscribeBlock([
		"MPXone_BossMap/$dev$.Integers. | MED_DOt",
		"MPXone_BossMap/$dev$.Integers. | MED_/AE",
		"MPXone_BossMap/$dev$.Digitals. | MED_FOt",
		"MPXone_BossMap/$dev$.Analogs. | MED_FAE",
		"MPXone_BossMap/$dev$.Integers. | MED_/AG"],
		function (e){

			var DoutCh = e[0].value;
			var AoutCh = e[1].value;
			var DoutStatus = e[2].value;
			var AoutSpeed = e[3].value;
			var CompAoutCh = e[4].value;

			var valueToPrint = "";		

			if (AoutCh != 0){
				if (typeof AoutSpeed == "number")
					valueToPrint = AoutSpeed.toFixed(1) + " %";
				else
					valueToPrint = "OFF";
			}else{
				if (DoutStatus)
					valueToPrint = "ON";
				else
					valueToPrint = "OFF";
			}

			webMI.gfx.setText("CondFanStatus",valueToPrint);

			if ((DoutCh != 0 || AoutCh != 0) && CompAoutCh != 0){ //Fan present
				webMI.gfx.setMoveY(idCondFanGroup, 0);

			}else{ //Fan not present
				webMI.gfx.setMoveY(idCondFanGroup, 1080);
			}

	});
}

//***************************************************
//******************* Compressor ********************
//***************************************************	

var idCompSpeedGroup = "CompSpeedGroup";

if (isBasic){

	webMI.gfx.setMoveY(idCompSpeedGroup, 1080);

}else{

	webMI.data.subscribeBlock([
		"MPXone_BossMap/$dev$.Integers. | MED_/AG",
		"MPXone_BossMap/$dev$.Analogs. | MED_FAG"],
		function (e){

			var AoutCh = e[0].value;
			var AoutSpeed = e[1].value;

			if (typeof AoutSpeed == "number")
				var valueToPrint = AoutSpeed.toFixed(1) + " %";
			else
				var valueToPrint = "OFF";

			webMI.gfx.setText("CompSpeed",valueToPrint);

			if (AoutCh != 0){ //Compressor present
				webMI.gfx.setMoveY(idCompSpeedGroup, 0);

			}else{ //Compressor not present
				webMI.gfx.setMoveY(idCompSpeedGroup, 1080);
			}

	});
}
