			webMI.gfx.setText(id2, text_off);
			//if(reserved == "true"){
				//alert("restrue");
				//webMI.gfx.setText("on_off", "OFF");
			//}
		}
		page_status = status;
	}// END function setStatus
},{},{"base":"","color_off":"#000000","color_on":"#000000","color_rail_off":"#aaaaaa","color_rail_on":"#aaaaaa","read_delay":"5","readonly":"true","reserved":"false","text_off":"","text_on":""}],"26":[function(webMI,window,document,self){var AggregateManager = webMI.callExtension("SYSTEM.LIBRARY.ATVISE.QUICKDYNAMICS.Aggregate Manager");

